import { NavLink, useNavigate } from "react-router-dom";
import { useAuth } from "../../context/AuthContext";

const adminLinks = [
  { to: "/admin", icon: "⊞", label: "Dashboard", end: true },
  { to: "/admin/users", icon: "👥", label: "Manage Users" },
  { to: "/admin/products", icon: "📦", label: "Manage Products" },
];

const userLinks = [
  { to: "/user", icon: "⊞", label: "Dashboard", end: true },
  { to: "/user/profile", icon: "👤", label: "Profile" },
  { to: "/user/orders", icon: "🛍️", label: "Orders" },
];

export default function Sidebar() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const links = user?.role === "admin" ? adminLinks : userLinks;

  const handleLogout = () => {
    logout();
    navigate("/login");
  };

  return (
    <aside className="sidebar">
      <div className="sidebar-brand">
        <span className="brand-icon">◈</span>
        <span className="brand-name"></span>
      </div>

      <div className="sidebar-role-badge">
        <span className={`role-pill ${user?.role}`}>{user?.role?.toUpperCase()}</span>
      </div>

      <nav className="sidebar-nav">
        <p className="nav-section-label">Navigation</p>
        {links.map(({ to, icon, label, end }) => (
          <NavLink
            key={to}
            to={to}
            end={end}
            className={({ isActive }) =>
              `nav-link ${isActive ? "active" : ""}`
            }
          >
            <span className="nav-icon">{icon}</span>
            <span className="nav-label">{label}</span>
          </NavLink>
        ))}
      </nav>

      <div className="sidebar-footer">
        <div className="user-info">
          <div className="avatar">{user?.avatar}</div>
          <div className="user-meta">
            <p className="user-name">{user?.name}</p>
            <p className="user-email">{user?.email}</p>
          </div>
        </div>
        <button className="logout-btn" onClick={handleLogout} title="Logout">
          ⏻
        </button>
      </div>
    </aside>
  );
}
